    { let _path = std::env::var("DD_RELFIX").or_else(|_| std::env::var("RELFIX")).unwrap_or("RELFIX".to_string()); match CobolFile::open_relative_output(&_path, 51) { Ok(h) => { _files.insert("FLATFILE".into(), h); { let _fs_str = format!("{:0>2}", FileStatus::Success); record.set_bytes("CUST-STAT", _fs_str.as_bytes()); } } Err(e) => { { let _fs_str = format!("{:0>2}", e); record.set_bytes("CUST-STAT", _fs_str.as_bytes()); } { let _es = format!("{:0>2}", e); let _ec = cobol_runtime::file_status_to_ec(&_es); if !_ec.is_empty() { cobol_runtime::set_file_exception("FLATFILE", &_es, "OPEN OUTPUT", _ec); } }   } } }
