/// Paragraph: FLAT-RECORD
fn v2_flat_record(record: &mut CobolRecord, _files: &mut std::collections::HashMap<String, CobolFile>) {
    record.fill_field("TSP2-RECORD", 0x20);
    cobol_move(record, "SUB", "REC-NUM");
    cobol_move(record, &format!("DATA-CUST-NUM({})", record.get_i64("SUB")), "C2-CUST-NUM");
    cobol_move(record, &format!("DATA-COMPANY({})", record.get_i64("SUB")), "C2-COMPANY");
    cobol_move(record, &format!("DATA-NO-TERMINALS({})", record.get_i64("SUB")), "C2-NO-TERMINALS");
    record.set_f64("C2-PK-DATE", 20070319_f64);
    if (record.get_i64("SUB") == 1 || record.get_i64("SUB") == 3 || record.get_i64("SUB") == 5 || record.get_i64("SUB") == 7 || record.get_i64("SUB") == 9 || record.get_i64("SUB") == 10 || record.get_i64("SUB") == 11) {
    record.set_bytes("C2-DISK", b"8417");
    } else {
    record.set_bytes("C2-DISK", b"8470");
    }
    {
    let _data = record.get_raw_bytes("TSP2-RECORD");
    let _rk = record.get_i64("REC-NUM") as u32;
    if let Some(fh) = _files.get_mut("FLATFILE") {
        match fh.relative_write(_rk, &_data) {
            Ok(()) => { { let _fs_str = format!("{:0>2}", FileStatus::Success); record.set_bytes("CUST-STAT", _fs_str.as_bytes()); } }
            Err(_fs) => { { let _fs_str = format!("{:0>2}", _fs); record.set_bytes("CUST-STAT", _fs_str.as_bytes()); } }
        }
    } else { let _fs = FileStatus::WriteNotAllowed; { let _fs_str = format!("{:0>2}", _fs); record.set_bytes("CUST-STAT", _fs_str.as_bytes()); } }
    }
}

